.btn-row { display: flex; gap: 8px; align-items: center; }
.btn-row-mt { display: flex; justify-content: space-between; align-items: center; margin-top: 12px; }

.provider-btn {
  appearance: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  color: #fff;
  background: var(--accent);
  border: 1px solid transparent;
  padding: 8px 16px;
  font-size: 0.8rem;
  font-weight: 500;
  transition: opacity 0.15s;
}

.provider-btn:hover { background: var(--accent-hover); }
.provider-btn:disabled { opacity: 0.4; cursor: default; }

.provider-btn-secondary {
  background: var(--surface2);
  color: var(--text);
  border: 1px solid var(--border);
}

.provider-btn-secondary:hover { background: var(--bg-hover); }

.provider-btn-sm {
  padding: 3px 10px;
  font-size: 0.75rem;
}

.provider-btn-danger {
  background: var(--error);
  color: #fff;
  border: 1px solid transparent;
}

